import SideMenu from '@/components/SideMenu.vue'

export default {
  name: 'items',
  props: ['inventory', 'addToCart'],
  data () {
    return {
      href: this.$route.params.href,
      items: require('../items.json')
    }
  },
  computed: {
    cartIsValid () {
      return this.inventory.color && this.inventory.qty && this.inventory.size
    }
  },
  methods: {
    changeImg () {
      if (this.items[this.href].src = this.items[this.href].scroll) {
        this.items[this.href].src = this.items[this.href].scroll
      }
    }
  },
  components: {
    SideMenu
  }
}
